  ('social-worker-moex-00451', 'social-worker', 'social-worker-moex-113-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '員工績效管理技術中「360度回饋法╱考評法」（360DegreeFeedback/Appraisals）是藉由多元績效 評估回饋機制來評估員工績效表現，下列何者不是其常見的績效評估面向？', '["自評（self-appraisal）：員工針對自己的表現進行自我評估", "隨機評量（random-appraisal）：由隨機或不特定人提供回饋", "同儕評量（peer-rating）：同儕之間相互評量", "多主管、矩陣式評量（supervisors,matrix-appraisal）：跨部門合作或團隊運用常見的多主管、矩 陣式考核"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:03+00:00", "source_pdf_sha1": "890a7ba83f8f", "answer_pdf_sha1": "96773571a3bf", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "103", "s": "0303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
