  ('social-worker-moex-00459', 'social-worker', 'social-worker-moex-113-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '某社會福利機構主任，為了鼓勵創新，對於年度預算總是尊重各部門提出新方案的預算需求，儘 量予以滿足；在有限的總額經費前提下，對於來年的機構預算編列，各部門透過管道爭取不遺餘 力，甚至吵得不可開交，於是該主任提出按機構組織績效「讓數字來說話」，做為各部門編列預算 的核定決策依據，屬於下列何種模式？', '["政治模式", "漸進增值模式", "歷史模式", "理性規劃模式"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:03+00:00", "source_pdf_sha1": "890a7ba83f8f", "answer_pdf_sha1": "96773571a3bf", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "103", "s": "0303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
